orm.querySelector('input[name="_method"]')?.value || form.method; const btn = form.querySelector('button[type="submit"]'); if (method.toUpperCase() === 'DELETE' && !confirm('Hapus data ini?')) return; const originalText = btn.innerHTML; btn.innerHTML = '...'; btn.disabled = true; fetch(action, { method: method, headers: { 'X-CSRF-TOKEN': document.querySelector('input[name="_token"]')?.value || '', 'Accept': 'application/json' } }).then(r => r.json()).then(res => { if (res.success) { if (method.toUpperCase() === 'DELETE') { const tr = form.closest('tr'); if (tr) { tr.style.backgroundColor = '#fee2e2'; setTimeout(() => tr.remove(), 400); } } else if (method.toUpperCase() === 'PUT') { const tr = form.closest('tr'); if (tr && res.data) { const viewsTd = tr.querySelector('td[data-label="Views"]'); const likesTd = tr.querySelector('td[data-label="Like"]'); const commentsTd = tr.querySelector('td[data-label="Komen"]'); const sourceTd = tr.querySelector('td[data-label="Source"] span'); if (viewsTd) viewsTd.innerText = res.data.views; if (likesTd) likesTd.innerText = res.data.likes; if (commentsTd) commentsTd.innerText = res.data.comments; if (sourceTd) { sourceTd.innerText = res.data.source; sourceTd.className = 'badge green'; } btn.innerHTML = 'Ok!'; setTimeout(() => { btn.innerHTML = 'Sync'; btn.disabled = false; }, 2000); return; } } } else { alert(res.message || 'Terjadi kesalahan.'); btn.innerHTML = originalText; btn.disabled = false; } }).catch(err => { alert('Terjadi kesalahan koneksi.'); btn.innerHTML = originalText; btn.disabled = false; }); } }); });</script>
